section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/feature-flag-cleanup-discipline.json",
  "title": "Feature Flag Cleanup Discipline",
  "type": "object",
  "required": [
    "artefact_id",
    "flag_name",
    "owner",
    "expiry",
    "cleanup_pr",
    "verified_removed_evidence",
    "metric_snapshot",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "flag_name": {
      "type": "string",
      "minLength": 1
    },
    "expiry": {
      "type": "string",
      "format": "date",
      "description": "ISO date when flag must be removed by"
    },
    "cleanup_pr": {
      "type": "string",
      "description": "URL or id of the PR that removes the flag"
    },
    "verified_removed_evidence": {
      "type": "string",
      "minLength": 1,
      "description": "grep output / coverage line"
    },
    "metric_snapshot": {
      "type": "object",
      "description": "{date, hit_count_last_7d, on_ratio}"
    }
  },
  "additionalProperties": false
}
